import { useEffect, useState } from "react";
import API from "../services/api";

export default function ExpertList() {
  const [experts, setExperts] = useState([]);

  useEffect(() => {
    fetchExperts();
  }, []);

  const fetchExperts = async () => {
    const res = await API.get("/experts");
    setExperts(res.data);
  };

  return (
    <div>
      <h3>Experts</h3>
      {experts.map((exp) => (
        <div key={exp._id}>
          {exp.name} - {exp.field}
        </div>
      ))}
    </div>
  );
}
